package form;
import model.User;import util.UIUtils;import javax.swing.*;import java.awt.*;
public class MainFrame extends JFrame{private final JPanel content=new JPanel(new BorderLayout());private final User user;public MainFrame(User user){this.user=user;setTitle("SKM - Sistem Keuangan Madrasah");setSize(1280,760);setLocationRelativeTo(null);setDefaultCloseOperation(EXIT_ON_CLOSE);setLayout(new BorderLayout());add(sidebar(),BorderLayout.WEST);add(content,BorderLayout.CENTER);showPage(new DashboardForm());}private JPanel sidebar(){JPanel s=new JPanel();s.setPreferredSize(new Dimension(250,0));s.setBackground(UIUtils.NAVY);s.setLayout(new BoxLayout(s,BoxLayout.Y_AXIS));JLabel logo=UIUtils.schoolLogo(74);logo.setAlignmentX(Component.CENTER_ALIGNMENT);s.add(Box.createVerticalStrut(18));s.add(logo);JLabel u=new JLabel(user.getNama()+" - "+user.getRole(),SwingConstants.CENTER);u.setForeground(UIUtils.WHITE);u.setAlignmentX(Component.CENTER_ALIGNMENT);s.add(u);String[] n={"Dashboard","Data Siswa & Kelas","Transaksi Pemasukan","Transaksi Pengeluaran","Tabungan Siswa","Laporan & Analitik","Pengaturan & Keamanan"};for(String x:n){JButton b=new JButton(x);b.setMaximumSize(new Dimension(230,42));b.setAlignmentX(Component.CENTER_ALIGNMENT);b.setForeground(UIUtils.WHITE);b.setBackground(UIUtils.NAVY);b.setFocusPainted(false);b.addActionListener(e->nav(x));s.add(Box.createVerticalStrut(8));s.add(b);}return s;}private void nav(String x){if(x.startsWith("Dashboard"))showPage(new DashboardForm());else if(x.startsWith("Data"))showPage(new SiswaForm());else if(x.contains("Pemasukan"))showPage(new PemasukanForm(user));else if(x.contains("Pengeluaran"))showPage(new PengeluaranForm(user));else if(x.contains("Tabungan"))showPage(new TabunganForm());else if(x.contains("Laporan"))showPage(new LaporanForm());else showPage(new PengaturanForm(user));}private void showPage(JPanel p){content.removeAll();content.add(p);content.revalidate();content.repaint();}}
